import{_ as o,o as c,c as d,a2 as t}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"Архитектура","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/architecture.md","filePath":"ru/guide/architecture.md"}'),r={name:"ru/guide/architecture.md"};function a(i,e,l,s,n,_){return c(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="архитектура" tabindex="-1">Архитектура <a class="header-anchor" href="#архитектура" aria-label="Permalink to &quot;Архитектура&quot;">​</a></h1><h2 id="как-работает-разрешение-resolution" tabindex="-1">Как работает разрешение (resolution) <a class="header-anchor" href="#как-работает-разрешение-resolution" aria-label="Permalink to &quot;Как работает разрешение (resolution)&quot;">​</a></h2><p><code>resolveFor()</code> - это ядро контекстной авторизации Clearance - см. <a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстную авторизацию</a> для полного API. Он объединяет три источника в следующем порядке приоритета:</p><ol><li><strong>Контекстные выдачи через роли</strong> - разрешения от ролей, которыми пользователь обладает именно в этом контексте (<code>clr_role_ctx</code>).</li><li><strong>Глобальные выдачи через роли</strong> - разрешения от глобально назначенных пользователю ролей Spatie (так <code>super_admin</code> и другие глобальные роли удовлетворяют <code>canIn()</code> для любого контекста).</li><li><strong>Переопределения по контексту</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> добавляет разрешение поверх вышеперечисленного; <code>forced_off</code> убирает его, даже если разрешение было выдано глобальной ролью. Запрет всегда побеждает.</li></ol><div class="warning custom-block"><p class="custom-block-title">Запрет всегда побеждает</p><p><code>forced_off</code> перекрывает любое разрешение, выданное глобальной ролью или контекстной выдачей через роль. Не существует способа &quot;перебить&quot; переопределение <code>forced_off</code> для той же пары пользователь/разрешение/контекст, кроме как удалить его.</p></div><h2 id="база-данных" tabindex="-1">База данных <a class="header-anchor" href="#база-данных" aria-label="Permalink to &quot;База данных&quot;">​</a></h2><p>Clearance владеет 6 таблицами и никогда не изменяет основные таблицы Spatie (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). Все внешние ключи, ссылающиеся на <code>roles.id</code>/<code>permissions.id</code>, каскадно удаляются, если не указано иное; таблицы Spatie не имеют внешних ключей, ссылающихся обратно на <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Таблица</th><th>Ключевые столбцы</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (уникальны вместе) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - метаданные отображения для роли или guard&#39;а</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (уникален, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (nullable FK -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - ceiling-роль</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (уникален), <code>driver</code>, <code>provider</code> - guard&#39;ы, управляемые через панель</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (уникален), <code>value</code> - хранилище ключ/значение времени выполнения (роль по умолчанию и т.д.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - контекстные назначения ролей, уникальны по <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - персональные, привязанные к контексту переопределения разрешений</td></tr></tbody></table><h2 id="никогда-не-трогает-таблицы-spatie" tabindex="-1">Никогда не трогает таблицы Spatie <a class="header-anchor" href="#никогда-не-трогает-таблицы-spatie" aria-label="Permalink to &quot;Никогда не трогает таблицы Spatie&quot;">​</a></h2><p>Clearance спроектирован так, чтобы работать рядом с <code>spatie/laravel-permission</code>, а не заменять его. Каждая запись <code>Role</code> и <code>Permission</code>, создаваемая или редактируемая панелью Clearance, - это настоящая модель Spatie, хранящаяся в собственных таблицах Spatie. Clearance никогда не выполняет миграцию, которая добавляет столбец в <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> или <code>role_has_permissions</code>, либо записывает в них внешний ключ.</p><p>Все собственные данные Clearance - метаданные отображения, область и ceiling ролей, контекстные назначения, переопределения по контексту, определения guard&#39;ов и настройки - хранятся исключительно в 6 таблицах <code>clr_*</code> выше. Это означает:</p><ul><li>Удаление Clearance никогда не рискует повредить существующие данные ролей/разрешений Spatie.</li><li>Любой код, который уже напрямую читает модели или таблицы Spatie, продолжает работать без изменений.</li><li>Контекстные и ceiling-функции Clearance - это чисто аддитивные слои, разрешаемые во время запроса (через <code>resolveFor()</code> и <code>RoleService</code>), а не встроенные в схему Spatie.</li></ul><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстная авторизация</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, директивы Blade, <code>ContextService</code></li><li><a href="/clearance-docs/ru/features/roles.html">Роли</a> - область и ceiling-роли, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/ru/guide/migration.html">Миграция</a> - заполнение <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> на существующей установке Spatie</li><li><a href="/clearance-docs/ru/guide/security.html">Безопасность</a> - как модель ceiling и переопределений предотвращает повышение привилегий</li></ul>',14)])])}const h=o(r,[["render",a]]);export{p as __pageData,h as default};
